Review this JavaScript function for coding convention compliance. Assume Prettier and ESLint are already configured.

```js
function processUserData(user) {
  if (user.isActive) {
    const profile = loadProfile(user.id);
    validateProfile(profile);
    const settings = loadSettings(user.id);
    validateSettings(settings);
    if (profile.isComplete && settings.areValid) {
      sendWelcomeEmail(user.email);
      logActivity(user.id, 'welcome_sent');
      updateUserStatus(user.id, 'onboarded');
    } else {
      throw new Error('Incomplete profile or invalid settings');
    }
  } else {
    throw new Error('User is not active');
  }
}
```
